mapper.select:
SELECT 
FROM domain_package_impact_preview
WHERE package_id = #{packageId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
  AND current_version_id = #{currentVersionId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
  AND candidate_version_id = #{candidateVersionId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
ORDER BY generated_at DESC
LIMIT 1

mapper.update:
UPDATE domain_package_impact_preview
SET confirmed_by = #{confirmedBy},
    confirmed_at = #{confirmedAt, typeHandler=com.pdp.persistence.typehandler.InstantTypeHandler}
WHERE id = #{id, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
  AND confirmed_by IS NULL
  AND confirmed_at IS NULL
  AND expires_at > #{now, typeHandler=com.pdp.persistence.typehandler.InstantTypeHandler}
